/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Features:
 * - Configurable transport: accepts an SmsTransport for actual delivery,
 *   defaulting to an in-memory store for testing.
 * - Phone number resolver: resolves recipient identifiers (user IDs) to
 *   phone numbers via a configurable resolver function.
 * - Message formatting: converts NotificationPayload into a concise SMS
 *   text body.
 *
 * Implements NotificationAdapter interface.
 * Adapters handle delivery only — they must NOT subscribe to EventBus directly.
 *
 * NOTE: User preferences currently only support email channel settings.
 * The preferences model (src/models/user-preferences.ts) needs to be updated
 * to support per-channel preferences (SMS enabled/disabled, SMS frequency, etc.)
 * before SMS notifications can be preference-gated. See decision records and
 * the warning posted to the blackboard for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Transport interface for SMS delivery.
 * Implement this for real providers (Twilio, AWS SNS, etc.).
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ success: boolean; error?: string }>;
}

/**
 * A formatted SMS message ready for transport.
 */
export interface SmsMessage {
  to: string;
  body: string;
  notificationId: string;
  sentAt: Date;
}

/**
 * Resolves a recipient identifier to a phone number.
 * For example, converts a userId to the user's phone number.
 * Returns null if the recipient cannot be resolved.
 */
export type PhoneNumberResolver = (recipient: string) => Promise<string | null>;

/**
 * Configuration for the SmsAdapter.
 */
export interface SmsAdapterConfig {
  transport?: SmsTransport;
  phoneNumberResolver?: PhoneNumberResolver;
}

/**
 * Default in-memory transport for testing.
 */
export class InMemorySmsTransport implements SmsTransport {
  private sentMessages: SmsMessage[] = [];

  async sendSms(message: SmsMessage): Promise<{ success: boolean; error?: string }> {
    this.sentMessages.push(message);
    return { success: true };
  }

  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  clear(): void {
    this.sentMessages = [];
  }
}

/**
 * Default phone number resolver — treats the recipient as a phone number if it
 * starts with '+', otherwise returns null (unresolvable).
 */
const defaultPhoneNumberResolver: PhoneNumberResolver = async (recipient: string) => {
  if (recipient.startsWith('+')) {
    return recipient;
  }
  return null;
};

/**
 * Format a NotificationPayload into a concise SMS text body.
 * SMS messages are length-limited, so we keep it brief.
 */
function formatSmsBody(payload: NotificationPayload): string {
  return `${payload.subject}: ${payload.body}`;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;
  private phoneNumberResolver: PhoneNumberResolver;

  constructor(config: SmsAdapterConfig = {}) {
    this.transport = config.transport ?? new InMemorySmsTransport();
    this.phoneNumberResolver = config.phoneNumberResolver ?? defaultPhoneNumberResolver;
  }

  /**
   * Send a notification via SMS.
   * 1. Resolves recipient to a phone number.
   * 2. Formats the payload as a concise text message.
   * 3. Delivers via the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const resolvedPhoneNumber = await this.phoneNumberResolver(payload.recipient);
    if (!resolvedPhoneNumber) {
      this.logger.warn(`Could not resolve phone number for recipient: ${payload.recipient}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: `Could not resolve phone number for recipient: ${payload.recipient}`,
        deliveredAt: new Date(),
      };
    }

    const message: SmsMessage = {
      to: resolvedPhoneNumber,
      body: formatSmsBody(payload),
      notificationId: payload.id,
      sentAt: new Date(),
    };

    this.logger.info(`Sending SMS to ${resolvedPhoneNumber}: ${payload.subject}`);

    try {
      const result = await this.transport.sendSms(message);

      if (!result.success) {
        this.logger.error(`SMS transport failed for ${payload.id}: ${result.error}`);
        return {
          success: false,
          notificationId: payload.id,
          channel: this.channel,
          error: result.error ?? 'SMS delivery failed',
          deliveredAt: new Date(),
        };
      }

      return {
        success: true,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: message.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`SMS transport error for ${payload.id}: ${errorMessage}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get the transport (useful for testing with InMemorySmsTransport).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }
}

export { formatSmsBody };

