import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
  formatSmsBody,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  SmsMessage,
  PhoneNumberResolver,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'sms',
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let transport: InMemorySmsTransport;
  let adapter: SmsAdapter;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ transport });
  });

  describe('channel', () => {
    it('should report sms channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('send', () => {
    it('should send an SMS successfully', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should deliver the formatted message to the phone number', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const messages = transport.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15551234567');
      expect(messages[0]?.body).toBe(
        'Order Confirmation: order-1: Your order has been placed. Items: Widget x2. Total: $20.00',
      );
      expect(messages[0]?.notificationId).toBe('notif-0001');
      expect(messages[0]?.sentAt).toBeInstanceOf(Date);
    });
  });

  describe('phone number resolution', () => {
    it('should resolve E.164 phone numbers directly', async () => {
      const payload = makePayload({ recipient: '+441234567890' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getSentMessages()[0]?.to).toBe('+441234567890');
    });

    it('should fail for non-phone-number recipients', async () => {
      const payload = makePayload({ recipient: 'user-123' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve phone number');
      expect(result.error).toContain('user-123');
      expect(transport.getSentMessages()).toHaveLength(0);
    });

    it('should use custom phone number resolver', async () => {
      const resolver: PhoneNumberResolver = async (recipient) => {
        if (recipient === 'user-alice') return '+15559876543';
        return null;
      };

      const adapterWithResolver = new SmsAdapter({ transport, phoneNumberResolver: resolver });
      const payload = makePayload({ recipient: 'user-alice' });
      const result = await adapterWithResolver.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getSentMessages()[0]?.to).toBe('+15559876543');
    });

    it('should fail when custom resolver returns null', async () => {
      const resolver: PhoneNumberResolver = async () => null;
      const adapterWithResolver = new SmsAdapter({ transport, phoneNumberResolver: resolver });
      const payload = makePayload({ recipient: 'unknown-user' });
      const result = await adapterWithResolver.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Could not resolve phone number');
    });
  });

  describe('transport errors', () => {
    it('should handle transport returning failure', async () => {
      const failingTransport: SmsTransport = {
        async sendSms(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'Carrier rejected message' };
        },
      };

      const failAdapter = new SmsAdapter({ transport: failingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Carrier rejected message');
    });

    it('should handle transport throwing an exception', async () => {
      const throwingTransport: SmsTransport = {
        async sendSms(): Promise<{ success: boolean; error?: string }> {
          throw new Error('Network timeout');
        },
      };

      const failAdapter = new SmsAdapter({ transport: throwingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Network timeout');
    });

    it('should handle non-Error throws', async () => {
      const throwingTransport: SmsTransport = {
        async sendSms(): Promise<{ success: boolean; error?: string }> {
          throw 'string error';
        },
      };

      const failAdapter = new SmsAdapter({ transport: throwingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('string error');
    });
  });

  describe('getTransport', () => {
    it('should return the configured transport', () => {
      expect(adapter.getTransport()).toBe(transport);
    });

    it('should default to InMemorySmsTransport', () => {
      const defaultAdapter = new SmsAdapter();
      expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemorySmsTransport);
    });
  });
});

describe('InMemorySmsTransport', () => {
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
  });

  it('should store sent messages', async () => {
    const message: SmsMessage = {
      to: '+15551234567',
      body: 'Test message',
      notificationId: 'notif-1',
      sentAt: new Date(),
    };

    const result = await transport.sendSms(message);
    expect(result.success).toBe(true);
    expect(transport.getSentMessages()).toHaveLength(1);
    expect(transport.getSentMessages()[0]?.to).toBe('+15551234567');
  });

  it('should clear messages', async () => {
    const message: SmsMessage = {
      to: '+15551234567',
      body: 'Test message',
      notificationId: 'notif-1',
      sentAt: new Date(),
    };

    await transport.sendSms(message);
    transport.clear();
    expect(transport.getSentMessages()).toHaveLength(0);
  });
});

describe('formatSmsBody', () => {
  it('should format payload into concise SMS text', () => {
    const payload = makePayload();
    const body = formatSmsBody(payload);

    expect(body).toBe(
      'Order Confirmation: order-1: Your order has been placed. Items: Widget x2. Total: $20.00',
    );
  });
});

